-- Rename all company_id columns to tenant_id for multi-tenant alignment\nDO \nDECLARE r record;\nBEGIN\n  FOR r IN\n    SELECT table_schema, table_name\n    FROM information_schema.columns\n    WHERE column_name = 'company_id' AND table_schema = 'public'\n  LOOP\n    EXECUTE format('ALTER TABLE %I.%I RENAME COLUMN company_id TO tenant_id;', r.table_schema, r.table_name);\n  END LOOP;\nEND;\n;\n
